use std::collections::HashMap;

struct Record {
    id: usize,
    data: String,
}

fn process_records(input_list: &Vec<String>) -> HashMap<usize, Vec<String>> {
    let mut results = HashMap::new();
    for line in input_list.iter() {
        if let Some(pos) = line.find(":") {
            let id_str = &line[..pos];
            let data_part = &line[pos + 1..];
            match id_str.trim().parse::<usize>() {
                Ok(id) => {
                    if let Some(record) = Some(Record { id, data: data_part.trim().to_string() }) {
                        let entry = results.entry(record.id).or_insert_with(Vec::new);
                        entry.push(format!("{}", record.data));
                    }
                },
                Err(_) => {}
            }
        }
    }
    results
}

use std::collections::HashMap;

struct VectorSearchIndex {
    data: HashMap<String, Vec<f64>>,
}

impl VectorSearchIndex {
    fn new() -> Self {
        VectorSearchIndex { data: HashMap::new() }
    }

    fn insert_vector(&mut self, key: impl ToString, vector: &[f64]) {
        self.data.insert(key.to_string(), vector.to_vec());
    }

    fn find_closest_vector(&self, query_vector: &[f64]) -> Option<String> {
        if self.data.is_empty() {
            return None;
        }

        let mut min_distance = f64::MAX;
        let mut closest_key: Option<String> = None;

        for (key, stored_vector) in &self.data {
            let distance = self.calculate_euclidean_distance(query_vector, stored_vector);
            if distance < min_distance {
                min_distance = distance;
                closest_key = Some(key.clone());
            }
        }
        closest_key
    }

    fn calculate_euclidean_distance(&self, a: &[f64], b: &[f64]) -> f64 {
        if a.len() != b.len() || a.is_empty() {
            return f64::NAN;
        }

        let sum_of_squares: f64 = a.iter().zip(b.iter()).map(|(&x, &y)| (x - y).powi(2)).sum();
        sum_of_squares.sqrt()
    }
}

fn main() {
    let mut index = VectorSearchIndex::new();
    index.insert_vector(1.to_string(), &[1.0, 1.0]);
    index.insert_vector(2.to_string(), &[5.0, 4.0]);
    index.insert_vector(3.to_string(), &[1.1, 1.05]);

    let query = &[1.05, 1.0];
    match index.find_closest_vector(query) {
        Some(key) => println!("Found closest vector key: {}", key),
        None => println!("Index is empty.")
    }
}

use std::collections::HashMap;

struct ConsensusState {
    members: Vec<String>,
    log_entries: Vec<i32>,
}

impl ConsensusState {
    fn new(members: Vec<String>, log_entries: Vec<i32>) -> Self {
        ConsensusState {
            members,
            log_entries,
        }
    }

    fn process_state(&self) -> HashMap<String, String> {
        let mut results = HashMap::new();

        match (&self.members, &self.log_entries) {
            (members_slice, log_slice) => match (members_slice.len(), log_slice.len()) {
                (3, 12) => {
                    results.insert("Full State".to_string(), format!("Ready to commit after processing {} logs.", log_slice[0]));
                },
                (2, _) => {
                    results.insert("Partial Members".to_string(), format!("Only two nodes are currently communicating."));
                },
                (1, _) => {
                    results.insert("Single Node".to_string(), "System running in degraded mode, requires immediate attention.".to_string());
                },
                (_, 0) => {
                    results.insert("Empty State".to_string(), "No data found for consensus calculation.".to_string());
                },
                (n, l) if n >= 2 && l > 12 => {
                    let msg = format!("Warning: {} members and {} logs detected. Proceeding with caution.", n, l);
                    results.insert("Overloaded".to_string(), msg);
                },
                (n, l) => {
                    results.insert("Unknown State".to_string(), format!("Unhandled state: {} members and {} logs.", n, l));
                }
            }
        }
        results
    }
}

fn main() {
    let state1 = ConsensusState::new(vec!["A".to_string(), "B".to_string(), "C".to_string()], vec![100, 101].into_iter().cycle().take(12).collect());
    println!("n--- State 1 ---");
    let results1 = state1.process_state();
    for (key, value) in results1 { println!("{}: {}", key, value); }

    let state2 = ConsensusState::new(vec!["X".to_string(), "Y".to_string()], vec![50].into_iter().collect());
    println!("n--- State 2 ---");
    let results2 = state2.process_state();
    for (key, value) in results2 { println!("{}: {}", key, value); }
}

