    fn new(data: Vec<f64>) -> Self {
        KeyScanner { data_sequence: data }
    }

    fn find_pattern(&self) -> Option<Vec<f64>> {
        let mut deque = VecDeque::new();
        for &value in self.data_sequence.iter() {
            deque.push_back(value);

            if deque.len() >= 4 {
                let first = deque[0];
                let second = deque[1];
                let third = deque[2];
                let fourth = deque[3];

                if (second - first).abs() < 1e-6 && 
                   (third - second).abs() < 1e-6 && 
                   (fourth - third).abs() < 1e-6 {
                    return Some(deque.iter().cloned().collect());
                }

                deque.pop_front();
            }
        }
        None
    }
